def validate(args, output):
    candidates, target = args[0], args[1]
    allowed = set(candidates)
    cand = sorted(set(candidates))
    correct = set()
    def bt(i, remaining, path):
        if remaining == 0:
            correct.add(tuple(path)); return
        if i >= len(cand):
            return
        v = cand[i]
        k = 0
        while v * k <= remaining:
            bt(i + 1, remaining - v * k, path + [v] * k)
            k += 1
    bt(0, target, [])
    seen = set()
    for combo in output:
        if not isinstance(combo, list):
            return False
        if not combo:
            return False
        if sum(combo) != target:
            return False
        for v in combo:
            if v not in allowed:
                return False
        key = tuple(sorted(combo))
        if key in seen:
            return False
        seen.add(key)
    return seen == correct

