function validate(args, output) {
    const candidates = args[0], target = args[1];
    const allowed = new Set(candidates);
    const cand = Array.from(new Set(candidates)).sort((a, b) => a - b);
    const correct = new Set();
    function bt(i, remaining, path) {
        if (remaining === 0) { correct.add(path.join(',')); return; }
        if (i >= cand.length) return;
        const v = cand[i];
        let k = 0;
        while (v * k <= remaining) {
            bt(i + 1, remaining - v * k, path.concat(Array(k).fill(v)));
            k++;
        }
    }
    bt(0, target, []);
    const seen = new Set();
    for (const combo of output) {
        if (!Array.isArray(combo)) return false;
        if (combo.length === 0) return false;
        if (combo.reduce((a, b) => a + b, 0) !== target) return false;
        for (const v of combo) if (!allowed.has(v)) return false;
        const key = combo.slice().sort((a, b) => a - b).join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

