class Solution:
    def combinationSum(self, candidates, target):
        cand = sorted(set(candidates))
        res = set()
        def bt(i, remaining, path):
            if remaining == 0:
                res.add(tuple(path)); return
            if i >= len(cand):
                return
            v = cand[i]
            k = 0
            while v * k <= remaining:
                bt(i + 1, remaining - v * k, path + [v] * k)
                k += 1
        bt(0, target, [])
        out = [list(t) for t in res]
        out.sort()
        return out

